class Solution:
    def numMovesStonesII(self, stones):
        s = sorted(stones)
        n = len(s)
        hi = s[-1]
        lo = s[0]
        present = set(s)
        best_min = n
        for start in range(lo, hi - n + 2):
            end = start + n - 1
            inside = sum(1 for p in s if start <= p <= end)
            empties = n - inside
            if inside == n - 1 and (start not in present or end not in present):
                cost = 2
            else:
                cost = empties
            if cost < best_min:
                best_min = cost
        max_moves = max(s[-1] - s[1], s[-2] - s[0]) - (n - 2)
        return [best_min, max_moves]

