class Solution:
    def numMovesStonesII(self, stones):
        s = sorted(stones)
        n = len(s)
        max_moves = max(s[-1] - s[1], s[-2] - s[0]) - (n - 2)
        min_moves = n
        j = 0
        for i in range(n):
            while s[i] - s[j] + 1 > n:
                j += 1
            count = i - j + 1
            if count == n - 1 and s[i] - s[j] + 1 == n - 1:
                min_moves = min(min_moves, 2)
            else:
                min_moves = min(min_moves, n - count)
        return [min_moves, max_moves]

