var numMovesStonesII = function(stones) {
    const s = stones.slice().sort((a, b) => a - b);
    const n = s.length;
    const maxMoves = Math.max(s[n - 1] - s[1], s[n - 2] - s[0]) - (n - 2);
    let minMoves = n;
    let j = 0;
    for (let i = 0; i < n; i++) {
        while (s[i] - s[j] + 1 > n) j++;
        const count = i - j + 1;
        if (count === n - 1 && s[i] - s[j] + 1 === n - 1) {
            minMoves = Math.min(minMoves, 2);
        } else {
            minMoves = Math.min(minMoves, n - count);
        }
    }
    return [minMoves, maxMoves];
};
